// Your JavaScript solution here

function binaryGap(N) {
  let binary = N.toString(2);
  let firstOne = binary.indexOf('1');
  let lastOne = binary.lastIndexOf('1');
  let maxGap = 0;
  for (let i = firstOne + 1; i <= lastOne; i++) {
    if (binary[i] === '0') {
      maxGap++;
    }
  }
  return maxGap;
}

